import { forwardRef, useCallback, useEffect, useId, useRef, useState } from 'react';
import { formatCharCount, getDefaultErrorMsg } from '@arvo/utils';
import { useTooltip } from '../../hooks/useTooltip';
import { FormLabel } from '../FormLabel';

export interface ArvoTextareaChangeDetail {
  value: string;
  previousValue: string;
}

export interface ArvoTextareaProps extends Omit<React.TextareaHTMLAttributes<HTMLTextAreaElement>, 'size'> {
  value?: string;
  placeholder?: string;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  label?: string;
  isRequired?: boolean;
  isInvalid?: boolean;
  size?: 'sm' | 'lg';
  icon?: string;
  rows?: number;
  maxLength?: number;
  hasCounter?: boolean;
  autoResize?: boolean;
  resizable?: 'none' | 'vertical' | 'both';
  errorMsg?: string;
  errorDisplay?: 'inline' | 'tooltip' | 'none';
  isLoading?: boolean;
  isFullWidth?: boolean;
  onInput?: React.FormEventHandler<HTMLTextAreaElement>;
  onChange?: React.ChangeEventHandler<HTMLTextAreaElement>;
  onFocus?: React.FocusEventHandler<HTMLTextAreaElement>;
  onBlur?: React.FocusEventHandler<HTMLTextAreaElement>;
}

const ArvoTextarea = forwardRef<HTMLDivElement, ArvoTextareaProps>(
  function ArvoTextarea(
    {
      value,
      placeholder,
      isDisabled = false,
      isReadOnly = false,
      label,
      isRequired = false,
      isInvalid = false,
      size = 'sm',
      icon,
      rows = 3,
      maxLength,
      hasCounter = false,
      autoResize = false,
      resizable = 'none',
      errorMsg,
      errorDisplay = 'inline',
      isLoading = false,
      isFullWidth = false,
      onInput,
      onChange,
      onFocus,
      onBlur,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `arvo-textarea-${uid}`;
    const errorId = `arvo-textarea-err-${uid}`;
    const counterId = `arvo-textarea-counter-${uid}`;
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const rootRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);
    const previousValueRef = useRef('');

    const isControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState('');

    const currentValue = isControlled ? value : internalValue;
    const errorMessage = errorMsg ?? getDefaultErrorMsg();
    const showTooltipIcon = isInvalid && errorDisplay === 'tooltip';
    const showInlineAlert = isInvalid && errorDisplay === 'inline';
    useTooltip({
      triggerRef: errIcoRef,
      tooltip: showTooltipIcon ? errorMessage : undefined,
    });

    const classes = [
      'arvo-textarea',
      `arvo-textarea--${size}`,
      isFullWidth && 'arvo-textarea--full-width',
      autoResize && 'arvo-textarea--auto-resize',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      showTooltipIcon && 'error-tooltip',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const recalcAutoResizeHeight = useCallback(() => {
      const el = textareaRef.current;
      if (!el || !autoResize) return;
      el.style.height = 'auto';
      el.style.height = `${el.scrollHeight}px`;
      el.style.overflow = el.scrollHeight > el.clientHeight ? 'auto' : 'hidden';
    }, [autoResize]);

    useEffect(() => {
      previousValueRef.current = currentValue;
    }, [currentValue]);

    useEffect(() => {
      if (autoResize) {
        recalcAutoResizeHeight();
      }
    }, [currentValue, autoResize, recalcAutoResizeHeight]);

    function handleInput(e: React.FormEvent<HTMLTextAreaElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      if (!isControlled) {
        setInternalValue(e.currentTarget.value);
      }
      onInput?.(e);
    }

    function handleChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      const newValue = e.target.value;
      const prev = previousValueRef.current;
      previousValueRef.current = newValue;
      if (!isControlled) {
        setInternalValue(newValue);
      }
      rootRef.current?.dispatchEvent(
        new CustomEvent<ArvoTextareaChangeDetail>('textarea:change', {
          bubbles: true,
          cancelable: true,
          detail: { value: newValue, previousValue: prev },
        })
      );
      onChange?.(e);
    }

    function handleFocus(e: React.FocusEvent<HTMLTextAreaElement>) {
      onFocus?.(e);
    }

    function handleBlur(e: React.FocusEvent<HTMLTextAreaElement>) {
      onBlur?.(e);
    }

    const resizeStyle = autoResize
      ? 'none'
      : resizable;

    function setRefs(node: HTMLDivElement | null) {
      (rootRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
    }

    const describedByParts: string[] = [];
    if (showInlineAlert) describedByParts.push(errorId);
    if (hasCounter && !showInlineAlert) describedByParts.push(counterId);
    const describedBy = describedByParts.length > 0 ? describedByParts.join(' ') : undefined;

    return (
      <div ref={setRefs} className={classes} role="group" aria-busy={isLoading || undefined}>
        {label && (
          <FormLabel htmlFor={inputId} size="sm" isRequired={isRequired} isDisabled={isDisabled} className="arvo-textarea__lbl">
            {label}
          </FormLabel>
        )}
        <div className="arvo-textarea__field">
          {icon && (
            <span className={`arvo-textarea__ico o9con o9con-${icon}`} aria-hidden="true" />
          )}
          <textarea
            ref={textareaRef}
            id={inputId}
            className="arvo-textarea__input"
            value={currentValue}
            placeholder={placeholder}
            disabled={isDisabled}
            readOnly={isReadOnly}
            required={isRequired}
            rows={rows}
            maxLength={maxLength}
            style={{ resize: resizeStyle }}
            aria-invalid={isInvalid || undefined}
            aria-required={isRequired || undefined}
            aria-describedby={describedBy}
            onInput={handleInput}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            {...rest}
          />
          {showTooltipIcon && (
            <span ref={errIcoRef} className="arvo-textarea__err-ico" aria-hidden="true" />
          )}
          <div className="arvo-textarea__border" />
        </div>
        {hasCounter && !showInlineAlert && (
          <span id={counterId} className="arvo-textarea__counter">
            {formatCharCount(currentValue.length, maxLength ?? null)}
          </span>
        )}
        {showInlineAlert && (
          <div className="arvo-inline-alert arvo-inline-alert--error" id={errorId} role="alert">
            <span className="arvo-inline-alert__ico" aria-hidden="true" />
            <span className="arvo-inline-alert__msg">{errorMessage}</span>
          </div>
        )}
      </div>
    );
  }
);

export default ArvoTextarea;
